using System.Runtime.InteropServices;

class EnvVarCheck
{
    // .NET 9 breaking change: GetEnvironmentVariable returns null for empty
    // env vars on Linux. Use native getenv to distinguish "not set" from "empty".
    [DllImport("libc", EntryPoint = "getenv", CharSet = CharSet.Ansi)]
    private static extern IntPtr NativeGetenv(string name);

    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        IntPtr ptr = NativeGetenv("MY_FLAG");
        if (ptr == IntPtr.Zero)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else
        {
            string val = Marshal.PtrToStringAnsi(ptr) ?? string.Empty;
            Console.WriteLine($"MY_FLAG is set to '{val}'");
        }
    }
}

